	AvgContextPerAgentChart,
	FailureReasonChart,
	RunsOverTimeChart,
	TopSeedsByContextChart,
} from "./run-analytics/Charts.tsx";
import { CommandCategoryChart, StuckCommandTable } from "./run-analytics/CommandMining.tsx";
import { TokenConsumptionChart } from "./run-analytics/TokenConsumptionChart.tsx";
import { InsightCallouts } from "./run-analytics/Insights.tsx";
import { KpiCards } from "./run-analytics/KpiCards.tsx";
import { GroupTable } from "./run-analytics/Tables.tsx";
import { TokenKpiCards, TokenGroupTable } from "./run-analytics/TokenStats.tsx";

/** Default date window: last 30 days. Mirrors the server default. */
function defaultFrom(): string {
	const d = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
	return d.toISOString().slice(0, 10);
}

export function RunAnalyticsPage() {
	const [searchParams, setSearchParams] = useSearchParams();
	const projectId = searchParams.get("projectId") ?? "";
	const from = searchParams.get("from") ?? defaultFrom();
	const to = searchParams.get("to") ?? "";

	const updateParam = (k: string, v: string) => {
		const next = new URLSearchParams(searchParams);
		if (v === "") next.delete(k);
		else next.set(k, v);
		setSearchParams(next, { replace: true });
	};

	const projects = useQuery({
		queryKey: ["projects"],
		queryFn: ({ signal }) => projectsApi.list(signal),
	});

	const analytics = useQuery({
		queryKey: ["analytics", "runs", { projectId, from, to }],
		queryFn: ({ signal }) =>
			runAnalyticsApi.runs(
				{
					...(projectId !== "" ? { projectId } : {}),
					...(from !== "" ? { from: `${from}T00:00:00.000Z` } : {}),
					...(to !== "" ? { to: `${to}T23:59:59.999Z` } : {}),
				},
				signal,
			),
	});

	const behavior = useQuery({
		queryKey: ["analytics", "behavior", { projectId, from, to }],
		queryFn: ({ signal }) =>
			runAnalyticsApi.behavior(
				{
					...(projectId !== "" ? { projectId } : {}),
					...(from !== "" ? { from: `${from}T00:00:00.000Z` } : {}),
					...(to !== "" ? { to: `${to}T23:59:59.999Z` } : {}),
				},
				signal,
			),
	});

	const data = analytics.data;
	const loading = analytics.isLoading;
	const behaviorData = behavior.data;

	return (
		<div className="space-y-6">
			<PageHeader
				title="Run analytics"
				description="Execution telemetry across runs — success, duration, context burn. Defaults to the last 30 days."
			/>

			<Card>
				<CardHeader>
					<CardTitle>Filters</CardTitle>
				</CardHeader>
				<CardContent>
					<div className="flex flex-wrap items-end gap-4">
						<div className="flex flex-col gap-1">
							<label htmlFor="ra-from" className="text-xs text-(--color-muted-foreground)">
								From
							</label>
							<input
								id="ra-from"
								type="date"
								value={from}
								onChange={(e) => updateParam("from", e.target.value)}
								className="rounded border border-(--color-border) bg-transparent px-2 py-1 text-sm"
							/>
						</div>
						<div className="flex flex-col gap-1">
							<label htmlFor="ra-to" className="text-xs text-(--color-muted-foreground)">
								To
							</label>
							<input
								id="ra-to"
								type="date"
								value={to}
								onChange={(e) => updateParam("to", e.target.value)}
								className="rounded border border-(--color-border) bg-transparent px-2 py-1 text-sm"
							/>
						</div>
						<div className="flex flex-col gap-1">
							<label htmlFor="ra-project" className="text-xs text-(--color-muted-foreground)">
								Project
							</label>
							<select
								id="ra-project"
								value={projectId}
								onChange={(e) => updateParam("projectId", e.target.value)}
								className="rounded border border-(--color-border) bg-transparent px-2 py-1 text-sm"
							>
								<option value="">All projects</option>
								{projects.data?.projects.map((p) => (
									<option key={p.id} value={p.id}>
										{p.gitUrl.replace(/^https:\/\/github\.com\//, "") || p.id}
									</option>
								))}
							</select>
						</div>
					</div>
				</CardContent>
			</Card>

			{analytics.isError ? (
				<Card>
					<CardContent className="py-6 text-sm text-(--color-destructive)">
						Failed to load run analytics.{" "}
						{(analytics.error as Error | null)?.message ?? ""}
					</CardContent>
				</Card>
			) : null}

			<InsightCallouts insights={behaviorData?.insights ?? []} />

			<KpiCards totals={data?.totals} />

			<div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
				<RunsOverTimeChart timeSeries={data?.timeSeries ?? []} />
				<FailureReasonChart byFailureReason={data?.byFailureReason ?? []} />
				<AvgContextPerAgentChart byAgent={data?.byAgent ?? []} />
				<TopSeedsByContextChart topSeeds={data?.topSeedsByContext ?? []} />
			</div>

			<div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
				<GroupTable
					title="By agent"
					subtitle="Run rollup per agent"
					dimension="agent"
					buckets={data?.byAgent ?? []}
					loading={loading}
				/>
				<GroupTable
					title="By model"
					subtitle="Run rollup per provider model"
					dimension="model"
					buckets={data?.byModel ?? []}
					loading={loading}
				/>
			</div>

			{behavior.isError ? (
				<Card>
					<CardContent className="py-6 text-sm text-(--color-destructive)">
						Failed to load command behavior.{" "}
						{(behavior.error as Error | null)?.message ?? ""}
					</CardContent>
				</Card>
			) : null}

			<TokenKpiCards totals={data?.tokens.totals} />

			{data ? (
				<TokenConsumptionChart
					timeSeries={data.tokens.timeSeries}
					byModelTimeSeries={data.tokens.byModelTimeSeries}
					byProviderTimeSeries={data.tokens.byProviderTimeSeries}
				/>
			) : null}

			<div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
				<TokenGroupTable
					title="Token usage by model"
					subtitle="Token breakdown per model"
					dimension="model"
					buckets={data?.byModel ?? []}
					loading={loading}
				/>
				<TokenGroupTable
					title="Token usage by provider"
					subtitle="Token breakdown per provider"
					dimension="provider"
					buckets={data?.byProvider ?? []}
					loading={loading}
				/>
			</div>

			<div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
				<CommandCategoryChart byCategory={behaviorData?.mining.byCategory ?? []} />
				<StuckCommandTable byStuckScore={behaviorData?.mining.byStuckScore ?? []} />
			</div>
		</div>
	);
}

/**
 * Token-consumption over-time chart for the Run Analytics dashboard
 * (warren-4dc9 / pl-d1a2 step 4).
 *
 * Stacked AreaChart of daily token counts with a segmented toggle
 * switching the stacking dimension:
 *   - "kind"     → stack by token kind (input/output/cacheRead/cacheWrite)
 *   - "model"    → stack one Area per model key
 *   - "provider" → stack one Area per provider key
 *
 * All recharts primitives come from the shared chart.tsx seam (warren-876c).
 * Y-axis and tooltip use formatTokens from format.ts.
 * Empty window shows the page's standard "No data in this window." text.
 */
import * as React from "react";
import type { DimensionTokenSeries, TokenDayBucket } from "@/api/client.ts";
import { RUN_ANALYTICS_NONE_KEY, RUN_ANALYTICS_OTHER_KEY } from "@/api/client.ts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card.tsx";
import {
	Area,
	AreaChart,
	CartesianGrid,
	ChartContainer,
	Legend,
	Tooltip,
	XAxis,
	YAxis,
} from "@/components/ui/chart.tsx";
import { formatTokens } from "./format.ts";

// ---------------------------------------------------------------------------
// Palette
// ---------------------------------------------------------------------------

const KIND_COLORS = {
	input: "var(--color-info)",
	output: "var(--color-success)",
	cacheRead: "var(--color-primary)",
	cacheWrite: "var(--color-warning)",
} as const;

/** A simple deterministic palette for model/provider series. */
const DIM_PALETTE = [
	"var(--color-info)",
	"var(--color-success)",
	"var(--color-primary)",
	"var(--color-warning)",
	"var(--color-destructive)",
	"var(--color-neutral)",
	"var(--color-muted-foreground)",
];

/** Visual de-emphasis for "other" and "unknown" roll-up series. */
const DE_EMPHASISED = new Set([RUN_ANALYTICS_OTHER_KEY, RUN_ANALYTICS_NONE_KEY]);

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const AXIS_PROPS = {
	stroke: "var(--color-muted-foreground)",
	fontSize: 11,
	tickLine: false,
	axisLine: false,
} as const;

const TOOLTIP_STYLE = {
	backgroundColor: "var(--color-card)",
	border: "1px solid var(--color-border)",
	borderRadius: 6,
	fontSize: 12,
} as const;

type Dimension = "kind" | "model" | "provider";

/**
 * Merge a `DimensionTokenSeries[]` into an array of flat chart objects keyed
 * by `date`, with one numeric entry per series key holding the series' daily
 * *total* tokens. Missing dates for a given key are filled with 0.
 */
function mergeDimensionSeries(
	dimSeries: readonly DimensionTokenSeries[],
): Record<string, number | string>[] {
	// Collect the union of all dates in insertion order of the first series.
	const dateSet = new Set<string>();
	for (const s of dimSeries) {
		for (const b of s.series) {
			dateSet.add(b.date);
		}
	}
	const dates = Array.from(dateSet).sort();
	if (dates.length === 0) return [];

	const rows: Record<string, number | string>[] = dates.map((d) => ({ date: d }));
	const dateIndex = new Map(dates.map((d, i) => [d, i]));

	for (const s of dimSeries) {
		for (const b of s.series) {
			const idx = dateIndex.get(b.date);
			if (idx !== undefined) {
				const row = rows[idx];
				if (row !== undefined) {
					row[s.key] = b.total;
				}
			}
		}
		// Fill zeros for dates this series is missing.
		for (const row of rows) {
			if (!(s.key in row)) row[s.key] = 0;
		}
	}
	return rows;
}

// ---------------------------------------------------------------------------
// Chart
// ---------------------------------------------------------------------------

export function TokenConsumptionChart({
	timeSeries,
	byModelTimeSeries,
	byProviderTimeSeries,
}: {
	timeSeries: readonly TokenDayBucket[];
	byModelTimeSeries: readonly DimensionTokenSeries[];
	byProviderTimeSeries: readonly DimensionTokenSeries[];
}) {
	// Default dimension is "kind".
	const [dim, setDim] = React.useState<Dimension>("kind");

	// Determine emptiness per dimension so the toggle still works even if
	// one dimension has no data.
	const empty =
		dim === "kind"
			? timeSeries.length === 0
			: dim === "model"
				? byModelTimeSeries.length === 0
				: byProviderTimeSeries.length === 0;

	return (
		<Card>
			<CardHeader>
				<div className="flex flex-wrap items-start justify-between gap-2">
					<div>
						<CardTitle className="text-base">Token consumption over time</CardTitle>
						<p className="text-xs text-(--color-muted-foreground)">
							Daily token counts — stacked by{" "}
							{dim === "kind" ? "token kind" : dim === "model" ? "model" : "provider"}
						</p>
					</div>
					<DimensionToggle value={dim} onChange={setDim} />
				</div>
			</CardHeader>
			<CardContent>
				{empty ? (
					<p className="py-6 text-sm text-(--color-muted-foreground)">No data in this window.</p>
				) : dim === "kind" ? (
					<KindChart timeSeries={timeSeries} />
				) : dim === "model" ? (
					<DimChart dimSeries={byModelTimeSeries} />
				) : (
					<DimChart dimSeries={byProviderTimeSeries} />
				)}
			</CardContent>
		</Card>
	);
}

// ---------------------------------------------------------------------------
// Segmented toggle
// ---------------------------------------------------------------------------

const DIMS: { value: Dimension; label: string }[] = [
	{ value: "kind", label: "By kind" },
	{ value: "model", label: "By model" },
	{ value: "provider", label: "By provider" },
];

function DimensionToggle({
	value,
	onChange,
}: {
	value: Dimension;
	onChange: (d: Dimension) => void;
}) {
	return (
		<div className="inline-flex rounded border border-(--color-border) text-xs">
			{DIMS.map((d) => (
				<button
					key={d.value}
					type="button"
					onClick={() => onChange(d.value)}
					className={[
						"px-2 py-1 transition-colors first:rounded-l last:rounded-r",
						value === d.value
							? "bg-(--color-primary) text-(--color-primary-foreground) font-medium"
							: "text-(--color-muted-foreground) hover:text-(--color-foreground)",
					].join(" ")}
				>
					{d.label}
				</button>
			))}
		</div>
	);
}

// ---------------------------------------------------------------------------
// Sub-charts
// ---------------------------------------------------------------------------

/**
 * recharts Tooltip `formatter`. Name comes from each `<Area name={…}>`
 * attribute; we only touch the value, returning a recharts tuple.
 * Omitting the `name` param entirely avoids NameType generics incompatibility
 * NameType in recharts 3.x is `string | number`, so we accept that union.
 */
function tokenFormatter(
	v: number | string | readonly (number | string)[] | undefined,
	name: string | number | undefined,
): [string, string] {
	const n = typeof v === "number" ? v : Number(v);
	return [formatTokens(Number.isFinite(n) ? n : 0), name == null ? "" : String(name)];
}

function KindChart({ timeSeries }: { timeSeries: readonly TokenDayBucket[] }) {
	return (
		<ChartContainer>
			<AreaChart data={timeSeries as TokenDayBucket[]} margin={{ top: 8, right: 8, bottom: 0, left: -16 }}>
				<CartesianGrid strokeDasharray="3 3" stroke="var(--color-border)" vertical={false} />
				<XAxis dataKey="date" {...AXIS_PROPS} />
				<YAxis tickFormatter={formatTokens} {...AXIS_PROPS} />
				<Tooltip contentStyle={TOOLTIP_STYLE} formatter={tokenFormatter} />
				<Legend wrapperStyle={{ fontSize: 11 }} />
				<Area
					type="monotone"
					dataKey="input"
					stackId="1"
					stroke={KIND_COLORS.input}
					fill={KIND_COLORS.input}
					fillOpacity={0.5}
					name="Input"
				/>
				<Area
					type="monotone"
					dataKey="output"
					stackId="1"
					stroke={KIND_COLORS.output}
					fill={KIND_COLORS.output}
					fillOpacity={0.5}
					name="Output"
				/>
				<Area
					type="monotone"
					dataKey="cacheRead"
					stackId="1"
					stroke={KIND_COLORS.cacheRead}
					fill={KIND_COLORS.cacheRead}
					fillOpacity={0.5}
					name="Cache read"
				/>
				<Area
					type="monotone"
					dataKey="cacheWrite"
					stackId="1"
					stroke={KIND_COLORS.cacheWrite}
					fill={KIND_COLORS.cacheWrite}
					fillOpacity={0.4}
					name="Cache write"
				/>
			</AreaChart>
		</ChartContainer>
	);
}

function DimChart({ dimSeries }: { dimSeries: readonly DimensionTokenSeries[] }) {
	const data = mergeDimensionSeries(dimSeries);
	const keys = dimSeries.map((s) => s.key);

	return (
		<ChartContainer>
			<AreaChart
				data={data}
				margin={{ top: 8, right: 8, bottom: 0, left: -16 }}
			>
				<CartesianGrid strokeDasharray="3 3" stroke="var(--color-border)" vertical={false} />
				<XAxis dataKey="date" {...AXIS_PROPS} />
				<YAxis tickFormatter={formatTokens} {...AXIS_PROPS} />
				<Tooltip contentStyle={TOOLTIP_STYLE} formatter={tokenFormatter} />
				<Legend wrapperStyle={{ fontSize: 11 }} />
				{keys.map((key, i) => {
					const color = DIM_PALETTE[i % DIM_PALETTE.length] ?? "var(--color-neutral)";
					const deEmphasised = DE_EMPHASISED.has(key);
					return (
						<Area
							key={key}
							type="monotone"
							dataKey={key}
							stackId="1"
							stroke={color}
							fill={color}
							fillOpacity={deEmphasised ? 0.2 : 0.5}
							strokeOpacity={deEmphasised ? 0.4 : 1}
							name={key === RUN_ANALYTICS_NONE_KEY ? "unknown" : key === RUN_ANALYTICS_OTHER_KEY ? "other" : key}
						/>
					);
				})}
			</AreaChart>
		</ChartContainer>
	);
}

/**
 * Token KPI cards and per-model / per-provider token stats tables for
 * the Run Analytics dashboard (warren-bbc6 / pl-d1a2 step 5).
 *
 * TokenKpiCards renders three summary cards sourced from
 * `tokens.totals`: total tokens, input/output split, and cache-read
 * share. Zeroes are shown (not NaN) when the window is empty.
 *
 * TokenGroupTable renders one row per model or provider bucket with
 * columns for each token kind, share-of-total, and cost per 1M tokens
 * (derived from the bucket's costUsd + tokens.total; divide-by-zero
 * guarded → '—'). Uses the RunGroupBucket shape (which carries both
 * tokens and costUsd) so no extra fetch is needed.
 */
import { RUN_ANALYTICS_NONE_KEY, type RunGroupBucket } from "@/api/client.ts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card.tsx";
import {
	Table,
	TableBody,
	TableCell,
	TableHead,
	TableHeader,
	TableRow,
} from "@/components/ui/table.tsx";
import { formatCostUsd, formatPercent, formatTokens, formatTokensOrDash } from "./format.ts";

// ---------------------------------------------------------------------------
// KPI cards
// ---------------------------------------------------------------------------

function TokenKpiCard({
	title,
	value,
	hint,
}: {
	title: string;
	value: React.ReactNode;
	hint?: React.ReactNode;
}) {
	return (
		<Card>
			<CardHeader className="pb-3">
				<CardTitle className="text-xs font-medium text-(--color-muted-foreground)">
					{title}
				</CardTitle>
			</CardHeader>
			<CardContent>
				<div className="font-mono text-2xl">{value}</div>
				{hint !== undefined ? (
					<p className="mt-1 text-xs text-(--color-muted-foreground)">{hint}</p>
				) : null}
			</CardContent>
		</Card>
	);
}

export function TokenKpiCards({
	totals,
}: {
	totals: { input: number; output: number; cacheRead: number; cacheWrite: number; total: number } | undefined;
}) {
	const dash = "—";

	const total = totals?.total ?? 0;
	const input = totals?.input ?? 0;
	const output = totals?.output ?? 0;
	const cacheRead = totals?.cacheRead ?? 0;
	const cacheReadShare = total > 0 ? cacheRead / total : null;

	return (
		<div className="grid grid-cols-2 gap-4 md:grid-cols-3">
			<TokenKpiCard
				title="Total tokens"
				value={totals === undefined ? dash : formatTokens(total)}
				hint={
					totals === undefined
						? undefined
						: `input ${formatTokensOrDash(input)} · output ${formatTokensOrDash(output)}`
				}
			/>
			<TokenKpiCard
				title="Input / Output split"
				value={
					totals === undefined
						? dash
						: total === 0
							? "—"
							: `${formatPercent(input / total)} in`
				}
				hint={
					totals === undefined
						? undefined
						: total === 0
							? undefined
							: `${formatPercent(output / total)} output`
				}
			/>
			<TokenKpiCard
				title="Cache-read share"
				value={totals === undefined ? dash : formatPercent(cacheReadShare)}
				hint={
					totals === undefined
						? undefined
						: `${formatTokensOrDash(cacheRead)} cache-read tokens`
				}
			/>
		</div>
	);
}

// ---------------------------------------------------------------------------
// Per-model / per-provider token stats table
// ---------------------------------------------------------------------------

function renderBucketKey(_dimension: "model" | "provider", key: string): React.ReactNode {
	if (key === RUN_ANALYTICS_NONE_KEY) {
		return <span className="text-(--color-muted-foreground)">—</span>;
	}
	return <span className="font-mono text-xs">{key}</span>;
}

/** Cost per 1M tokens, guarding divide-by-zero. */
function costPer1M(costUsd: number, total: number): string {
	if (total === 0) return "—";
	return formatCostUsd((costUsd / total) * 1_000_000);
}

export function TokenGroupTable({
	title,
	subtitle,
	dimension,
	buckets,
	loading,
}: {
	title: string;
	subtitle: string;
	dimension: "model" | "provider";
	buckets: RunGroupBucket[];
	loading: boolean;
}) {
	const grandTotal = buckets.reduce((s, b) => s + b.tokens.total, 0);

	return (
		<Card>
			<CardHeader>
				<CardTitle className="text-base">{title}</CardTitle>
				<p className="text-xs text-(--color-muted-foreground)">{subtitle}</p>
			</CardHeader>
			<CardContent>
				{loading ? (
					<p className="text-sm text-(--color-muted-foreground)">Loading…</p>
				) : buckets.length === 0 ? (
					<p className="text-sm text-(--color-muted-foreground)">No data in this window.</p>
				) : (
					<Table>
						<TableHeader>
							<TableRow>
								<TableHead>{dimension === "model" ? "Model" : "Provider"}</TableHead>
								<TableHead className="text-right">Input</TableHead>
								<TableHead className="text-right">Output</TableHead>
								<TableHead className="text-right">Cache R</TableHead>
								<TableHead className="text-right">Cache W</TableHead>
								<TableHead className="text-right">Total</TableHead>
								<TableHead className="text-right">Share</TableHead>
								<TableHead className="text-right">$/1M</TableHead>
							</TableRow>
						</TableHeader>
						<TableBody>
							{buckets.map((b) => (
								<TableRow key={b.key}>
									<TableCell className="max-w-[200px] truncate">
										{renderBucketKey(dimension, b.key)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{formatTokens(b.tokens.input)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{formatTokens(b.tokens.output)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{formatTokens(b.tokens.cacheRead)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{formatTokens(b.tokens.cacheWrite)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs font-medium">
										{formatTokens(b.tokens.total)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{grandTotal === 0 ? "—" : formatPercent(b.tokens.total / grandTotal)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{costPer1M(b.costUsd, b.tokens.total)}
									</TableCell>
								</TableRow>
							))}
						</TableBody>
					</Table>
				)}
			</CardContent>
		</Card>
	);
}

/**
 * Formatting helpers for the Run Analytics dashboard (warren-638a /
 * pl-ad0f step 5).
 *
 * Kept in a dedicated module so the page + its sub-components share one
 * set of token / duration / percentage formatters without re-importing
 * RunDetail internals (formatTokens there is module-private). The cost
 * formatter is the one shared piece — re-exported from RunDetail so the
 * sub-cent rounding rule (mx-9d987a) stays in lockstep.
 */
export { formatCostUsd } from "../RunDetail.tsx";

/** 1_234_567 → "1.2M", 12_345 → "12.3k", 999 → "999". */
export function formatTokens(n: number): string {
	if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
	if (n >= 1_000) return `${(n / 1_000).toFixed(1)}k`;
	return String(Math.round(n));
}

/** Round-trip a possibly-null token count through formatTokens, em-dash on null. */
export function formatTokensOrDash(n: number | null): string {
	return n === null ? "—" : formatTokens(n);
}

/** Milliseconds → compact human duration ("4.2s", "3.1m", "1.4h"). */
export function formatDurationMs(ms: number | null): string {
	if (ms === null) return "—";
	if (ms < 1_000) return `${Math.round(ms)}ms`;
	const s = ms / 1_000;
	if (s < 60) return `${s.toFixed(1)}s`;
	const m = s / 60;
	if (m < 60) return `${m.toFixed(1)}m`;
	return `${(m / 60).toFixed(1)}h`;
}

/** 0..1 ratio → "92%", null → "—". */
export function formatRate(rate: number | null): string {
	if (rate === null) return "—";
	return `${Math.round(rate * 100)}%`;
}

/** Integer count, em-dash when the underlying value is null. */
export function formatCount(n: number | null): string {
	return n === null ? "—" : n.toLocaleString();
}

/** 0..1 ratio → "92.3%", null → "—". Higher precision than formatRate. */
export function formatPercent(ratio: number | null): string {
	if (ratio === null) return "—";
	return `${(ratio * 100).toFixed(1)}%`;
}

